		    p2q  = dot(p2,q)
		    p3q  = dot(p3,q)
		    p4q  = dot(p4,q)
		    kq = dot(k,q)

	    elseif(channel.eq.'tch') then
		    amu=ame
		    p1p2 = dot(p1,-p3)
		    p1p3 = dot(p1,-p2)
		    p1p4 = dot(p1,p4)
		    kp1  = dot(p1,k)
		    p2p3 = dot(p2,p3)
		    p2p4 = dot(-p3,p4)
		    kp2  = dot(-p3,k)
		    kp3 = dot(-p2,k)
		    p3p4 = dot(-p2,p4)
